// // This JK-latch will set Q to 0 when J is high and K is low, and toggle Q when J and K are both high.
module JK_latch (  
    input J,  
    input K,  
    input clk,  
    output reg Q  
);  
    always @(posedge clk) begin  
        if (J && !K)  
            Q <= 1;  
        else if (!J && K)  
            Q <= 0;  
        else if (J && K)  
            Q <= ~Q;  
        // If J = 0 and K = 0, Q remains unchanged  
    end  
endmodule
